import React, { useState, useMemo } from 'react';
import { Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { sxService } from '../../../services/sx/sxService';
import type { StageTrackingDto } from '../../../services/sx/models';
import { formatNumber, formatPercent } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

interface ProductivityRow {
  stageId: string;
  stageName: string;
  totalOut: number;
  totalIn: number;
  totalDefect: number;
  efficiency: number;
}

function monthRange(month: number, year: number) {
  const from = new Date(year, month - 1, 1).toISOString().slice(0, 10);
  const to = new Date(year, month, 0).toISOString().slice(0, 10);
  return { from, to };
}

const NangSuatPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [rows, setRows] = useState<StageTrackingDto[]>([]);
  const [loading, setLoading] = useState(false);

  const monthOptions = Array.from({ length: 12 }, (_, i) => ({
    value: String(i + 1),
    label: `Tháng ${i + 1}`,
  }));
  const yearOptions = [year - 1, year, year + 1].map(y => ({ value: String(y), label: String(y) }));
  const handleSearch = () => setReloadKey(k => k + 1);
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const { from, to } = monthRange(month, year);
    const t = setTimeout(() => {
      sxService
        .getStageTracking({ fromDate: from, toDate: to, page: 1, pageSize: 500 })
        .then(res => { if (!cancelled) setRows(res.items); })
        .catch(err => {
          if (!cancelled)
            dispatch(addToast({ message: err?.message ?? 'Lỗi tải năng suất', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [month, year, dispatch, reloadKey]);

  const aggregated = useMemo(() => {
    const map: Record<string, ProductivityRow> = {};
    for (const r of rows) {
      if (!map[r.stageId]) {
        map[r.stageId] = {
          stageId: r.stageId,
          stageName: r.stageName,
          totalOut: 0,
          totalIn: 0,
          totalDefect: 0,
          efficiency: 0,
        };
      }
      map[r.stageId].totalOut += r.outQty;
      map[r.stageId].totalIn += r.inQty;
      map[r.stageId].totalDefect += r.defectQty;
    }
    return Object.values(map).map(row => ({
      ...row,
      efficiency: formatPercent(row.totalOut, row.totalIn || row.totalOut || 1),
    }));
  }, [rows]);

  const totals = aggregated.reduce(
    (acc, r) => ({ out: acc.out + r.totalOut, in: acc.in + r.totalIn, defect: acc.defect + r.totalDefect }),
    { out: 0, in: 0, defect: 0 },
  );
  const avgEfficiency = formatPercent(totals.out, totals.in || totals.out || 1);

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-chart-line" /> Năng suất sản xuất T{month}/{year}</h1>
        </div>
      </div>

      <div className={styles.filtersBar} data-testid={`erp-nang-suat-filters`}>
        <Select value={String(month)} onChange={e => setMonth(Number(e.target.value))} options={monthOptions} size="small" />
        <Select value={String(year)} onChange={e => setYear(Number(e.target.value))} options={yearOptions} size="small" />
      </div>

      <div className={styles.summaryBar}>
        <div className={styles.summaryItem}><label className={styles.label}>Tổng SL ra</label><strong>{formatNumber(totals.out)}</strong></div>
        <div className={styles.summaryItem}><label className={styles.label}>Hiệu suất TB</label><strong>{avgEfficiency}%</strong></div>
        <div className={styles.summaryItem}><label className={styles.label}>SL lỗi</label><strong>{formatNumber(totals.defect)}</strong></div>
        <ListSearchRefreshButtons testIdPrefix="erp-nang-suat" onSearch={handleSearch} onRefresh={refresh} showSearch={false} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : aggregated.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu năng suất trong kỳ</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Công đoạn</th>
                  <th className={styles.colRight}>SL vào</th>
                  <th className={styles.colRight}>SL ra</th>
                  <th className={styles.colRight}>SL lỗi</th>
                  <th className={styles.colRight}>Hiệu suất</th>
                </tr>
              </thead>
              <tbody>
                {aggregated.map(r => (
                  <tr key={r.stageId}>
                    <td>{r.stageName}</td>
                    <td className={styles.colRight}>{formatNumber(r.totalIn)}</td>
                    <td className={styles.colRight}>{formatNumber(r.totalOut)}</td>
                    <td className={styles.colRight}>{formatNumber(r.totalDefect)}</td>
                    <td className={styles.colRight}>
                      <span style={{ color: r.efficiency >= 100 ? '#217A3C' : r.efficiency >= 80 ? '#d46b08' : '#C33A00', fontWeight: 600 }}>
                        {r.efficiency}%
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default NangSuatPage;
